class Solution {
    public boolean reorderedPowerOf2(int n) {
        String str = Integer.toString(n);
        char[] chars = str.toCharArray();
        Arrays.sort(chars);
        for (int i = 0; i < 31; i++) {
            long pow = 1L << i;
            String powStr = Long.toString(pow);
            char[] powChars = powStr.toCharArray();
            Arrays.sort(powChars);
            if (Arrays.equals(chars, powChars)) {
                return true;
            }
        }
        return false;
    }
}
